<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Algorithm Visualizer</title>
    <style>
        :root {
            --bg-color: #121212;
            --container-bg: #1e1e1e;
            --text-color: #e0e0e0;
            --bar-color: #4a90e2;
            --accent-color: #bb86fc;
            --button-bg: #333333;
            --button-hover: #444444;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
        }

        .app-container {
            background-color: var(--container-bg);
            padding: 2rem;
            border-radius: 12px;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
            text-align: center;
        }

        h1 {
            margin-top: 0;
            font-weight: 300;
            letter-spacing: 1px;
        }

        #bars {
            display: flex;
            align-items: flex-end;
            justify-content: center;
            height: 350px;
            width: 600px;
            gap: 2px;
            margin: 2rem 0;
            border-bottom: 2px solid #444;
            padding-bottom: 5px;
        }

        .bar {
            background-color: var(--bar-color);
            width: 100%;
            border-radius: 2px 2px 0 0;
            transition: height 0.1s ease;
        }

        .controls {
            display: flex;
            gap: 1rem;
            justify-content: center;
        }

        button {
            padding: 10px 24px;
            font-size: 1rem;
            cursor: pointer;
            background-color: var(--button-bg);
            color: white;
            border: 1px solid #555;
            border-radius: 6px;
            transition: all 0.2s ease;
        }

        button:hover {
            background-color: var(--button-hover);
            border-color: var(--accent-color);
        }

        button:active {
            transform: translateY(1px);
        }

        button:disabled {
            opacity: 0.5;
            cursor: not-allowed;
        }
    </style>
</head>
<body>

<div class="app-container">
    <h1>Sorting Visualizer</h1>
    <div id="bars"></div>
    <div class="controls">
        <button id="shuffle">Shuffle</button>
        <button id="sort">Sort</button>
        <button id="reset">Reset</button>
    </div>
</div>

<script>
    /**
     * State Management
     */
    let currentArray = [];
    let bubbleI = 0;
    let bubbleJ = 0;

    const barsContainer = document.getElementById('bars');

    /**
     * Rendering Logic
     */
    function render() {
        barsContainer.innerHTML = '';
        if (currentArray.length === 0) return;

        const maxVal = Math.max(...currentArray, 1);

        currentArray.forEach(val => {
            const bar = document.createElement('div');
            bar.className = 'bar';
            // Height is proportional to value
            const heightPercent = (val / maxVal) * 100;
            bar.style.height = `${heightPercent}%`;
            barsContainer.appendChild(bar);
        });
    }

    /**
     * Programmatic API
     */
    window.viz = {
        array: () => currentArray,

        setArray: (a) => {
            currentArray = [...a];
            // Reset sorting state machine
            bubbleI = 0;
            bubbleJ = 0;
            render();
        },

        sortStep: () => {
            // Bubble Sort Step-by-Step Implementation
            if (bubbleI >= currentArray.length) {
                return true; // Fully sorted
            }

            if (bubbleJ < currentArray.length - bubbleI - 1) {
                if (currentArray[bubbleJ] > currentArray[bubbleJ + 1]) {
                    // Swap elements
                    const temp = currentArray[bubbleJ];
                    currentArray[bubbleJ] = currentArray[bubbleJ + 1];
                    currentArray[bubbleJ + 1] = temp;
                }
                bubbleJ++;
            } else {
                bubbleI++;
                bubbleJ = 0;
            }

            render();
            return false; // Not finished yet
        },

        sorted: () => {
            for (let k = 0; k < currentArray.length - 1; k++) {
                if (currentArray[k] > currentArray[k + 1]) return false;
            }
            return true;
        }
    };

    /**
     * UI Interaction Logic
     */
    const shuffleBtn = document.getElementById('shuffle');
    const sortBtn = document.getElementById('sort');
    const resetBtn = document.getElementById('reset');

    function generateRandomArray(size = 40) {
        return Array.from({ length: size }, () => Math.floor(Math.random() * 95) + 5);
    }

    // Initialize
    window.viz.setArray(generateRandomArray());

    shuffleBtn.addEventListener('click', () => {
        window.viz.setArray(generateRandomArray());
    });

    resetBtn.addEventListener('click', () => {
        window.viz.setArray(generateRandomArray());
    });

    sortBtn.addEventListener('click', async () => {
        sortBtn.disabled = true;
        shuffleBtn.disabled = true;
        resetBtn.disabled = true;

        // Drive the sort step-by-step until sorted() is true
        while (!window.viz.sorted()) {
            const finished = window.viz.sortStep();
            if (finished) break;

            // Control animation speed
            await new Promise(resolve => setTimeout(resolve, 30));
        }

        sortBtn.disabled = false;
        shuffleBtn.disabled = false;
        resetBtn.disabled = false;
    });
</script>

</body>
</html>
